module traffic_light
(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output reg red
);
parameter idle = 2'b00;
parameter s1_red = 2'b01;
parameter s2_yellow = 2'b10;
parameter s3_green = 2'b11;
reg [7:0] cnt;
reg [1:0] state;
reg p_red, p_yellow, p_green;
always @(*) begin
    case (state)
        idle: begin
            state = s1_red;
            p_red = 0;
            p_yellow = 0;
            p_green = 0;
        end
        s1_red: begin
            if (cnt == 3) begin
                state = s3_green;
                p_red = 0;
                p_yellow = 0;
                p_green = 1;
            end else begin
                state = s1_red;
                p_red = 1;
                p_yellow = 0;
                p_green = 0;
            end
        end
        s2_yellow: begin
            if (cnt == 3) begin
                state = s1_red;
                p_red = 1;
                p_yellow = 0;
                p_green = 0;
            end else begin
                state = s2_yellow;
                p_red = 0;
                p_yellow = 1;
                p_green = 0;
            end
        end
        s3_green: begin
            if (cnt == 3) begin
                state = s2_yellow;
                p_red = 0;
                p_yellow = 1;
                p_green = 0;
            end else begin
                state = s3_green;
                p_red = 0;
                p_yellow = 0;
                p_green = 1;
            end
        end
    endcase
end
always @(*) begin
    if (!rst_n) begin
        cnt = 10;
    end else begin
        if (pass_request && green) begin
            cnt = 10;
        end else begin
            if (!green && p_green) begin
                cnt = 60;
            end else begin
                if (!yellow && p_yellow) begin
                    cnt = 5;
                end else begin
                    if (!red && p_red) begin
                        cnt = 10;
                    end
                end
            end
        end
    end
end
assign clock = cnt;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        red = p_red;
        yellow = p_yellow;
        green = p_green;
    end else begin
        red = p_red;
        yellow = p_yellow;
        green = p_green;
    end
end
endmodule
